import { useState } from 'react';
//import { format, Locale } from 'date-fns';
import './App.css';
import Api from './axios/api';
import { format} from 'date-fns';

interface Usuario {
  id: number;
  nome: string;
  cpf: string;
  telefone: string;
  dia_agendado: string;
  hora_agendada:string;
  data:string
  //status: string;
}

function App() {
const [usuarios, setUsuarios] =useState<Usuario[]>([{} as Usuario]);
const [nome,setNome]=useState("")
  const [cpf, setCpf] = useState("")
  const [telefone, setTelefone] = useState("")
  const [diaAgendado,setDiaAgendado] = useState("")
  const [HoraAgendada, setHoraAgendada] = useState("")
 //const formattedDate = format(new Dat), 'dd,MM, yyyy ');
const BuscarTodosUsuarios= async () => {
  console.log("Buscando todos os usuários...");
 await Api.get("",{
    params:{
    planilha:"usuario"
  }
  }
).then((response)=>{      
setUsuarios(response.data)
  console.log("Usuários encontrados:", usuarios);   
 }
).catch((e)=> console.log(e));
// console.log("Usuários encontrados:", format(usuarios[3].dia_agendado, "dd/MM/yyyy") ); 
}

const CadastrarUsuario = async () => {
//  e.preventDefault();
  const usuario: Usuario = {
    id:Number.parseInt(cpf.concat(telefone)), 
    nome: nome,   
    cpf:cpf,
    telefone: telefone,
    dia_agendado: diaAgendado,
    hora_agendada: HoraAgendada,
    data: format(new Date(), "dd/MM/yyyy").toString(), 
  }
   await Api.post("",usuario).then(
    (response) => {
      console.log("Usuario cadastrado com sucesso:", response.data);
    }
  )
   .catch((e) => console.log("Erro ao cadastrar usuário:", e));

   console.log("Usuário cadastrado:", usuario);
}


return (
    <div style={{display:'flex',flexDirection:"column"}}>
      <h1>Hello Mumi Braids!</h1>
      <h4> Site de Agendamento</h4>      



    {/* <th>Nome</th>     
    <th>CPF</th>
    <th>Telefone</th>
    <th>Dia Agendado</th>
    <th>Hora Agendada</th>
    <th>Data</th>  
     */}
    <div style={{ display: "flex", flexDirection: "column",border:10,borderColor:"black"}}>
      <div style={
        {
          display: "flex",
          flex: 1,
          flexDirection: "row",  
          margin: 10,
          ///alignItems: "center",
          justifyContent: "space-around",
          width: "60%",          
          paddingLeft: 10,
        }
      }>
      <h2 style={{ flex: 1 }}>NOME</h2>
        <h2 style={{ flex: 1}}>CPF</h2>
        <h2 style={{ flex: 1}}>Telefone</h2>
        <h2 style={{ flex: 1 }}>DIA</h2>
        <h2 style={{ flex: 1 }}>HORA</h2>
        <h2 style={{ flex: 1}}>DATA</h2>
</div>

  {usuarios.map((usuario) => (   
    <div style={
      {display:"flex",
      flex:1,
      flexDirection:"row",
      backgroundColor:"gray",
       margin:10,
       alignItems:"center",
       justifyContent:"space-around",
       width:"60%",
        borderRadius:10,
        paddingLeft:10,
       }
       }>
      <h2 style={{ flex: 1,fontSize:18 }}>{usuario.nome}</h2>
      <h2 style={{ flex: 1, fontSize: 18 }}>{usuario.cpf}</h2>
      <h2 style={{ flex: 1, fontSize: 18 }}>{usuario.telefone}</h2>
      <h2 style={{ flex: 1, fontSize: 18  }}>{usuario.dia_agendado}</h2>
      <h2 style={{ flex: 1, fontSize: 18 }}>{usuario.hora_agendada}</h2>   
      <h2 style={{ flex: 1, fontSize: 18 }}>{usuario.data}</h2>   
      </div>     

  ))}
    </div>



    <div>
      <button onClick={BuscarTodosUsuarios}>  Visuaisar</button>
      </div>
<div >
      <form action={CadastrarUsuario}  style={{display:"flex",flexDirection: "column" ,width:"30%",margin:10 }}>        
    <input type="text" value={nome} onChange={(e)=>setNome(e.target.value)} placeholder='Nome' style={{margin:10}} />
        <input type="text" value={cpf} onChange={(e) => setCpf(e.target.value)} placeholder='CPF' style={{ margin: 10 }} />
        <input type="text" value={telefone} onChange={(e) => setTelefone(e.target.value)} placeholder='Telefone' style={{ margin: 10 }} />
        <input type="text" value={diaAgendado} onChange={(e) => setDiaAgendado(e.target.value.toString())} placeholder='Dia Agendado' style={{ margin: 10 }} />
        <input type="text" value={HoraAgendada}  onChange={(e)=>setHoraAgendada(e.target.value.toString())} placeholder='Hora Agendada' style={{ margin: 10 }} />
        <input type="text" value={format(new Date(),"dd/MM/yyy").toString()} onChange={()=>{}} placeholder='Data' style={{ margin: 10 }} />        
        <button type="submit"  style={{ margin: 10,backgroundColor:"blue",fontSize:16,fontWeight:"bold" }}>Cadastrar</button>
        <button type="reset" style={{ margin: 10 }}>Limpar</button>
  </form>
</div>

    </div> 
  );
}

export default App;
